// Flutter imports:
import 'package:flutter/widgets.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';

// Project imports:
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/views/hooks/use_widget_ref.dart';
import 'package:baseball_detector_flutter/views/routers/app_router.dart';

VoidCallback useAuthNavigation() {
  final context = useContext();
  final ref = useWidgetRef();

  return useCallback(() {
    final isInSignUpFlow = ref.read(profileStorageProvider).getIsInSignUpFlow();

    if (isInSignUpFlow == null) {
      // Never started sign up flow -> new user
      Navigator.of(context).pushReplacementNamed(AppRouter.signUpPage);
    } else if (isInSignUpFlow) {
      // Currently in sign up flow - push SignUpPage then ConfirmCodePage
      Navigator.of(context).pushReplacementNamed(AppRouter.signUpPage);
      Navigator.of(context).pushNamed(AppRouter.confirmCodePage);
    } else {
      // Sign up flow completed (isInSignUpFlow == false) -> registered user
      Navigator.of(context).pushReplacementNamed(AppRouter.loginPage);
    }
  });
}

