    31→abstract class AuthClient {
    32→  Future<Result<Failure, bool>> signInWithPassword(
    33→    String email,
    34→    String password,
    35→    bool saveCredentials,
    36→  );
    37→
    38→  Future<Result<Failure, bool>> signOut();
    39→
    40→  Future<Result<Failure, bool>> changePassword({
    41→    required String newPassword,
    42→    required bool saveCredentials,
    43→  });
