    56→
    57→  Future<Result<Failure, void>> completeSignUp({required String token});
    58→
    59→  Future<Result<Failure, bool>> deleteAccount();
    60→
    61→  Future<bool> get isLoggedIn;
    62→}
    63→
    64→class AuthClientImpl extends AuthClient {
    65→  static final _fc = failureCodeBuilder.category('AAC'); // Auth-AuthClient
    66→  static final _logger = FimberLog('AuthClient');
    67→
    68→  late final APIServerClient _apiClient;
    69→
    70→  QueryRunner get _runner => _apiClient.runner;
    71→
    72→  /// local storage provider
    73→  final ProfileStorage _profileStorage;
    74→
    75→  /// Default constructor
    76→  AuthClientImpl(
    77→    this._profileStorage,
    78→    Locale locale,
    79→    String? appVersion,
    80→  ) {
    81→    _apiClient = APIServerClient(
    82→      locale: locale,
    83→      appVersion: appVersion,
    84→    );
    85→  }
    86→
    87→  @override
    88→
    89→  /// Sign in user to the application with email and password
    90→  Future<Result<Failure, bool>> signInWithPassword(
    91→      String email, String password, bool saveCredentials) async {
    92→    final methodFc = _fc.category('SIP');
    93→
    94→    // Run the query and return result.
    95→    final result = await _runner.runQuery(
    96→      () async {
    97→        if (await AuthUtils.instance.isSignedIn()) {
    98→          await AuthUtils.instance.signOut();
    99→        }
   100→        await Amplify.Auth.signIn(
   101→          username: email,
   102→          password: password,
   103→          options: const SignInOptions(
   104→            pluginOptions: CognitoSignInPluginOptions(
   105→              authFlowType: AuthenticationFlowType.userPasswordAuth,
   106→            ),
   107→          ),
   108→        );
   109→      },
   110→      false,
   111→    );
   112→    if (result.hasLeft) {
   113→      if (result.left is NetworkFailure) {
   114→        return Left(Failure.network(
   115→          code: methodFc.position('001'),
   116→          description: (l10n) =>
   117→              l10n.auth_client__failed_to_authenticate_check_network,
   118→          underlyingException: result.left.underlyingException,
   119→        ));
   120→      }
   121→      if (result.left is InvalidSessionFailure) {
   122→        final e = result.left.underlyingException;
   123→        if (e is AuthException) {
   124→          return Left(await _processAuthException(
   125→            e,
   126→            email: email,
   127→            password: password,
   128→          ));
   129→        }
   130→      }
   131→      return Left(result.left);
   132→    }
   133→
   134→    late String userId;
   135→    try {
   136→      userId = await AuthUtils.instance.getUserId();
   137→    } catch (e, stackTrace) {
   138→      _logger.e('failed to get userId', ex: e, stacktrace: stackTrace);
   139→      return Left(Failure.undefined(
   140→        code: methodFc.position('002'),
   141→        underlyingException: e,
   142→        stackTrace: stackTrace,
   143→      ));
   144→    }
   145→
   146→    await _profileStorage.setEmail(email);
   147→    if (saveCredentials) {
   148→      // Cache user password
   149→      await _profileStorage.setPassword(password);
   150→    } else {
   151→      // Remove cached user password
   152→      await _profileStorage.setPassword(null);
   153→    }
   154→
   155→    await _profileStorage.setUserId(userId);
   156→
   157→    // Get team_id and role of the user using direct API call
   158→    // This avoids circular dependency with Repository
   159→    final userInfoResult = await _apiClient.request(
   160→      method: 'GET',
   161→      path: '/users/me',
   162→      responseMapper: UserDetailResponse.fromJson,
   163→    );
   164→    if (userInfoResult.hasLeft) {
   165→      return Left(userInfoResult.left);
   166→    }
   167→
   168→    final user = userInfoResult.right.user;
   169→    final teamId = user.teams
   170→        .where((t) =>
   171→            user.givenUserRoles[t.id!]
   172→                ?.where((r) => !r.deleteFlag)
   173→                .isNotEmpty ??
   174→            false)
   175→        .firstOrNull
   176→        ?.id;
   177→    if (teamId == null) {
   178→      return Left(Failure.undefined(
   179→        code: methodFc.position('003'),
   180→        description: (l10n) => 'User does not belong to any team',
   181→      ));
   182→    }
   183→
   184→    // Cache team_id and role
   185→    await _profileStorage.setTeamId(teamId);
   186→
   187→    return const Right(true);
   188→  }
   189→
   190→  Future<Failure> _processAuthException(
   191→    AuthException e, {
   192→    required String email,
   193→    required String password,
   194→  }) async {
   195→    final methodFc = _fc.category('PAEX');
   196→
   197→    final isPasswordIncorrect = e is AuthNotAuthorizedException ||
   198→        (e is UserNotFoundException &&
   199→            e.message == "UserMigration failed with error Incorrect password.");
   200→    final isUserNotFound =
   201→        e is UserNotFoundException && e.message == "User does not exist.";
   202→
   203→    if (isPasswordIncorrect) {
   204→      // パスワードが間違っている場合でも、メール確認状況をチェック
   205→      final emailStatusResult = await _getEmailVerificationStatus(
   206→        email: email,
   207→        password: password,
   208→      );
   209→      // もしメール未確認の場合は、そちらのエラーを返す
   210→      if (emailStatusResult is UnconfirmedEmailFailure) {
   211→        return emailStatusResult;
   212→      }
   213→      // それ以外の場合は、パスワード間違いエラーを返す
   214→      return Failure.incorrectPassword(
   215→        code: methodFc.position('001'),
   216→        email: email,
   217→      );
   218→    }
   219→    if (isUserNotFound) {
   220→      return await _getEmailVerificationStatus(
   221→        email: email,
   222→        password: password,
   223→      );
   224→    }
   225→
   226→    // アカウント削除後にユーザーが削除予定に入っている場合に signIn しようとすると
   227→    // このエラーになる。この場合は未登録メールアドレスエラーを返す。
   228→    final errorCode = methodFc.position('003');
   229→    if (errorCode == 'EM-AAC-PAEX-003') {
   230→      return Failure.unregisteredEmail(
   231→        code: errorCode,
   232→        email: email,
   233→      );
   234→    }
   235→
   236→    // それ以外の認証エラーは UndefinedFailure として扱う
   237→    return Failure.undefined(
   238→      code: methodFc.position('004'),
   239→      description: (l10n) =>
   240→          l10n.auth_client__failed_to_authenticate_received_error_response,
   241→      underlyingException: e,
   242→    );
   243→  }
   244→
   245→  Future<Failure> _getEmailVerificationStatus({
   246→    required String email,
   247→    required String password,
   248→  }) async {
   249→    final methodFc = _fc.category('GVS');
   250→
   251→    // Run the query and return result.
   252→    final result = await _apiClient.request(
   253→      method: 'GET',
   254→      path:
   255→          '/auth/users/verification-status?email=${Uri.encodeQueryComponent(email)}',
   256→      responseMapper: EmailVerificationStatusResponse.fromJson,
   257→      authenticated: false,
   258→    );
   259→    if (result.hasLeft) {
   260→      return result.left;
   261→    }
   262→
   263→    final status = result.right.status;
   264→    switch (status) {
   265→      case EmailVerificationStatus.notVerified:
   266→        // メール未検証の場合
   267→        // この場合には localStorage に保存されている email, password, birthday の情報が
   268→        // このユーザーのものでない可能性があるため上書きする
   269→        // またメール未検証ということは一度 signUp をしているためサーバー上には birthday の情報がある
   270→        // そのため birtyday は null にして良い
   271→        // See also: https://knowhere-org.slack.com/archives/C080L18MC7M/p1759482517683899?thread_ts=1759457850.493329&cid=C080L18MC7M
   272→        await _profileStorage.setEmail(email);
   273→        await _profileStorage.setPassword(password);
   274→        await _profileStorage.setUserBirthday(null);
   275→        return Failure.unconfirmedEmail(
   276→          code: methodFc.position('001'),
   277→          email: email,
   278→        );
   279→      case EmailVerificationStatus.notCreated:
   280→        return Failure.unregisteredEmail(
   281→          code: methodFc.position('002'),
   282→          email: email,
   283→        );
   284→      default:
   285→        return Failure.undefined(
   286→          code: methodFc.position('003'),
   287→          description: (l10n) => l10n.auth_client__unknown_verification_status,
   288→        );
   289→    }
   290→  }
   291→
   292→  @override
   293→
   294→  /// Sign out user from application
   295→  Future<Result<Failure, bool>> signOut() async {
   296→    // TODO: After disconnecting network,
   297→    // goTrueClient.signOut() throws a network exception at the first call,
   298→    // but this method return null without any exceptions at the second call.
   299→
   300→    // Run the query and return result.
   301→    final result = await _runner.runQuery(
   302→      () => AuthUtils.instance.signOut(),
   303→    );
   304→    // Delete cache regardless of the result
   305→    await Future.wait([
   306→      _profileStorage.setUserId(null),
   307→      _profileStorage.setTeamId(null),
   308→    ]);
   309→    if (result.hasLeft) {
   310→      return Left(result.left);
   311→    } else {
   312→      return const Right(true);
   313→    }
   314→  }
   315→
   316→  @override
   317→  Future<Result<Failure, bool>> changePassword(
   318→      {required String newPassword, required bool saveCredentials}) async {
   319→    // Run the query and return result.
   320→    final result = await _apiClient.request(
   321→      method: 'PUT',
   322→      path: '/users/me/password',
   323→      data: PasswordChangeRequest(
   324→        password: newPassword,
   325→        passwordConfirmation: newPassword,
   326→      ).toJson(),
   327→    );
   328→    if (result.hasLeft) {
   329→      return Left(result.left);
   330→    }
   331→
   332→    if (saveCredentials) {
   333→      // Save if we need to save credentials
   334→      await _profileStorage.setPassword(newPassword);
   335→    } else {
   336→      // Remove cached user password
   337→      await _profileStorage.setPassword(null);
   338→    }
   339→    return const Right(true);
   340→  }
   341→
   342→  @override
   343→  Future<Result<Failure, bool>> forgotPassword({required String email}) async {
   344→    // Run the query and return result.
   345→    final result = await _apiClient.request(
   346→      method: 'POST',
   347→      path: '/auth/password-reset/email',
   348→      data: PasswordResetRequest(
   349→        email: email,
   350→      ).toJson(),
   351→      authenticated: false,
   352→    );
   353→    if (result.hasLeft) {
   354→      return Left(result.left);
   355→    }
   356→    return const Right(true);
   357→  }
   358→
   359→  @override
   360→  Future<Result<Failure, String>> signUp({
   361→    required String email,
   362→    required String password,
   363→    DateTime? birthday,
   364→  }) async {
   365→    final result = await _apiClient.request(
   366→      method: 'POST',
   367→      path: '/auth/signup',
   368→      data: SignUpRequest(
   369→        name: email,
   370→        email: email,
   371→        password: password,
   372→        birthday: birthday,
   373→      ).toJson(),
   374→      responseMapper: SignUpResponse.fromJson,
   375→      authenticated: false,
   376→    );
   377→    if (result.hasLeft) {
   378→      return Left(result.left);
   379→    }
   380→
   381→    final userId = result.right.userId;
   382→    await Future.wait([
   383→      _profileStorage.setIsInSignUpFlow(true),
   384→      _profileStorage.setEmail(email),
   385→      _profileStorage.setPendingSignUpUserId(userId),
   386→      _profileStorage.setUserId(userId),
   387→      _profileStorage.setPassword(password),
   388→      _profileStorage.setUserBirthday(birthday),
   389→    ]);
   390→    return Right(userId);
   391→  }
   392→
   393→  // API の内部的には signUp と同じ
   394→  @override
   395→  Future<Result<Failure, String>> resendCode() async {
   396→    final email = await _profileStorage.getEmail();
   397→    assert(email != null, 'email must not be null');
   398→
   399→    final result = await _apiClient.request(
   400→      method: 'POST',
   401→      path: '/auth/signup/resend',
   402→      data: ResendCodeRequest(
   403→        email: email!,
   404→      ).toJson(),
   405→      authenticated: false,
   406→      responseMapper: SignUpResponse.fromJson,
   407→    );
   408→    if (result.hasLeft) {
   409→      return Left(result.left);
   410→    }
   411→
   412→    final userId = result.right.userId;
   413→    await Future.wait([
   414→      _profileStorage.setIsInSignUpFlow(true),
   415→      _profileStorage.setPendingSignUpUserId(userId),
   416→      _profileStorage.setUserId(userId),
   417→    ]);
   418→    return Right(userId);
   419→  }
   420→
   421→  @override
   422→  Future<Result<Failure, String>> verifyCode({
   423→    required String code,
   424→  }) async {
   425→    final email = await _profileStorage.getEmail();
   426→    assert(email != null);
   427→
   428→    // Run the query and return result.
   429→    final result = await _apiClient.request(
   430→      method: 'GET',
   431→      path: '/auth/code-verification',
   432→      queryParameters: VerifyCodeRequest(
   433→        email: email!,
   434→        code: code,
   435→      ).toJson(),
   436→      responseMapper: VerifyCodeResponse.fromJson,
   437→      authenticated: false,
   438→    );
   439→    if (result.hasLeft) {
   440→      return Left(result.left);
   441→    }
   442→    return Right(result.right.token);
   443→  }
   444→
   445→  @override
   446→  Future<Result<Failure, void>> completeSignUp({required String token}) async {
   447→    final pendingUserId = _profileStorage.getPendingSignUpUserId();
   448→    final userId = pendingUserId ?? _profileStorage.getUserId();
   449→    final password = await _profileStorage.getPassword();
   450→
   451→    assert(userId != null);
   452→    assert(password != null);
   453→
   454→    // Run the query and return result.
   455→    final result = await _apiClient.request(
   456→      method: 'PUT',
   457→      path: '/auth/password-reset/initial',
   458→      data: SetUserInitialPasswordRequest(
   459→        userId: userId!,
   460→        password: password!,
   461→        token: token,
   462→      ).toJson(),
   463→      authenticated: false,
   464→    );
   465→    await Future.wait([
   466→      _profileStorage.setIsInSignUpFlow(false),
   467→      _profileStorage.setPendingSignUpUserId(null),
   468→    ]);
   469→    if (result.hasLeft) {
   470→      return Left(result.left);
   471→    }
   472→    return Right(null);
   473→  }
   474→
   475→  @override
   476→  Future<Result<Failure, bool>> deleteAccount() async {
   477→    // Run the query and return result.
   478→    final result = await _apiClient.request(
   479→      method: 'DELETE',
   480→      path: '/users/me',
   481→    );
   482→    if (result.hasLeft) {
   483→      return Left(result.left);
   484→    }
   485→
   486→    // Sign out and clear all cached data after successful account deletion
   487→    await Future.wait([
   488→      AuthUtils.instance.signOut(),
   489→      _profileStorage.setUserId(null),
   490→      _profileStorage.setTeamId(null),
   491→      _profileStorage.setEmail(null),
   492→      _profileStorage.setPassword(null),
   493→      _profileStorage.setIsInSignUpFlow(false),
   494→    ]);
   495→
   496→    return const Right(true);
   497→  }
   498→
   499→  @override
   500→  Future<bool> get isLoggedIn async {
   501→    return await AuthUtils.instance.isSignedIn();
   502→  }
   503→}
