/// {@category Containers}
library;

// Flutter imports:
import 'package:flutter/gestures.dart';
import 'package:flutter/material.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/login_state_controller.dart';
import 'package:baseball_detector_flutter/data/models/failure/bad_request_failure.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/utils/date.dart';
import 'package:baseball_detector_flutter/views/components/custom_button.dart';
import 'package:baseball_detector_flutter/views/components/custom_password_text_field.dart';
import 'package:baseball_detector_flutter/views/components/custom_text_form_field.dart';
import 'package:baseball_detector_flutter/views/components/login_layout.dart';
import 'package:baseball_detector_flutter/views/constants/input_max_lengths.dart';
import 'package:baseball_detector_flutter/views/hooks/use_operation.dart';
import 'package:baseball_detector_flutter/views/hooks/use_privacy_policy.dart';
import 'package:baseball_detector_flutter/views/hooks/use_single_action.dart';
import 'package:baseball_detector_flutter/views/hooks/use_terms_of_use.dart';
import 'package:baseball_detector_flutter/views/routers/app_router.dart';
import 'package:baseball_detector_flutter/views/themes/font_manager.dart';
import 'package:baseball_detector_flutter/views/validators/email.dart';
import 'package:baseball_detector_flutter/views/validators/password.dart';

class SignUpPage extends HookConsumerWidget {
  const SignUpPage({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final emailController = useTextEditingController();
    final birthdayController = useTextEditingController();
    final passwordController = useTextEditingController();
    final handleOperation = useOperation();
    final isLoading = useState(false);
    final isChecked = useState(false);
    final emailError = useState<EmailError?>(null);
    final birthday = useState<DateTime?>(null);
    final birthdayError = useState<String?>(null);
    final passwordError = useState<PasswordError?>(null);
    final checkboxError = useState<String?>(null);
    final openTermsOfUse = useTermsOfUse();
    final openPrivacyPolicy = usePrivacyPolicy();

    // 多重サインアップ防止
    final runSignUp = useSingleAction<void>(asyncCallback: (_) async {
      isLoading.value = true;

      // Validate password
      passwordError.value = validatePassword(
        password: passwordController.text,
      );

      // Validate email
      emailError.value = validateEmailAddress(emailController.text);

      // Validate birthday
      final selectedBirthday = birthday.value;
      if (selectedBirthday == null) {
        birthdayError.value = context.l10n.sign_up_page__birthday_required;
      } else if (_calculateAge(selectedBirthday) < 13) {
        birthdayError.value =
            context.l10n.sign_up_page__birthday_error_under_13;
      } else {
        birthdayError.value = null;
      }

      // Validate checkbox
      checkboxError.value =
          isChecked.value ? null : context.l10n.sign_up_page__terms_error;

      if (passwordError.value != null ||
          emailError.value != null ||
          birthdayError.value != null ||
          checkboxError.value != null) {
        isLoading.value = false;
        return;
      }

      await handleOperation(
        operation: ref.read(loginStateControllerProvider.notifier).signUp(
              emailController.text,
              passwordController.text,
              birthday.value!,
            ),
        onSucceeded: (_) {
          isLoading.value = false;
          Navigator.of(context).pushNamed(
            AppRouter.confirmCodePage,
            arguments: {
              'email': emailController.text,
            },
          );
          return null;
        },
        onFailed: (failure) {
          isLoading.value = false;
          return failure.translate(context.l10n);
        },
        // 既にユーザーが存在するエラーはは実装の不備ではないので、エラーログを送信しない
        shouldSendErrorLog: (failure) =>
            failure is! UserAlreadyExistsFailure &&
            failure is! AlreadyInUseFailure &&
            failure is! UnprocessableEntityFailure,
      );
    });

    return LoginLayout(
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          CustomTextFormField(
            controller: emailController,
            label: Text(
              context.l10n.sign_up_page__email_label,
              style: Theme.of(context).textTheme.bodyMedium?.copyWith(
                    fontWeight: FontWeight.w500,
                  ),
            ),
            keyboardType: TextInputType.emailAddress,
            maxLength: InputMaxLengths.email,
            errorText: translateEmailError(
              context,
              emailError.value,
            ),
            onChanged: (value) {
              emailError.value = null;
            },
          ),
          const Gap(16),
          CustomPasswordTextField(
            controller: passwordController,
            label: Text(
              context.l10n.sign_up_page__password_label,
              style: Theme.of(context).textTheme.bodyMedium?.copyWith(
                    fontWeight: FontWeight.w500,
